parameters.jsCode:
const items = $input.all();
const processed = [];

for (let i = 0; i < items.length; i++) {
  const json = items[i].json;

  let cleanText = "";

  // 1. If Google provided the 'text' field, use it directly without stripping tags
  if (json.text) {
    // Just normalize the spaces/newlines to keep the payload clean
    cleanText = json.text.replace(/\s+/g, ' ').trim();
  } 
  // 2. Fallback: If there is ONLY HTML available, then we strip the tags
  else if (json.textAsHtml || json.html) {
    const rawHtml = json.textAsHtml || json.html;
    cleanText = rawHtml.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  } 
  // 3. Absolute fallback
  else {
    cleanText = json.snippet || '';
  }

  // Safely extract the sender's email address
  let senderEmail = 'unknown@sender.com';
  if (json.from && json.from.value && json.from.value.length > 0) {
    senderEmail = json.from.value[0].address;
  } else if (json.from && json.from.text) {
    senderEmail = json.from.text;
  }

  processed.push({
    json: {
      message_id: json.id || json.messageId || `email-${Date.now()}-${i}`,
      sender_email: senderEmail,
      subject: json.subject || '(No Subject)',
      body_text: cleanText 
    }
  });
}

return processed;

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  // Extract the string, parse it, and overwrite the item's json completely
  const rawString = items[i].json.message?.content || items[i].json.choices?.[0]?.message?.content || "{}";
  items[i].json = JSON.parse(rawString);
}

return items;
